import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const logout = () => {
    localStorage.clear();
    navigate('/login');
  };

  return (
    <nav className="fixed top-4 left-1/2 -translate-x-1/2 w-[90%] z-[100] px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl flex justify-between items-center">
      <Link to="/" className="text-2xl font-black bg-gradient-to-r from-purple-400 to-pink-600 bg-clip-text text-transparent">
        TASK.IO
      </Link>
      <div className="flex gap-6 items-center">
        {!token ? (
          <>
            <Link to="/login" className="text-white hover:text-purple-400">Login</Link>
            <Link to="/signup" className="bg-purple-600 px-4 py-2 rounded-xl text-white font-bold">Get Started</Link>
          </>
        ) : (
          <button onClick={logout} className="text-red-400 font-bold">Logout</button>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
